import{_ as t,a,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as l,o as n,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"S3 Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/s3.md","filePath":"my/upload/s3.md","lastUpdated":1781962217000}'),c={name:"my/upload/s3.md"};function r(p,e,h,u,m,b){return n(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="s3-channel-ထည့်သွင်းခြင်း" tabindex="-1">S3 Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#s3-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;S3 Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="ဘယ်အချိန်မှာ-သုံးသင့်လဲ" tabindex="-1">ဘယ်အချိန်မှာ သုံးသင့်လဲ <a class="header-anchor" href="#ဘယ်အချိန်မှာ-သုံးသင့်လဲ" aria-label="Permalink to &quot;ဘယ်အချိန်မှာ သုံးသင့်လဲ&quot;">​</a></h2><p>S3 channel ကို ဒီအခြေအနေတွေမှာသုံးပါ:</p><ul><li>Cloudflare R2, Backblaze B2, MinIO, AWS S3 သို့မဟုတ် S3-compatible object storage service တစ်ခုခုကို connect လုပ်ချင်လျှင်။</li><li>standard S3 configuration model ဖြစ်တဲ့ <code>Endpoint</code>, Access Key, Secret Key ကိုသုံးချင်လျှင်။</li><li>native Cloudflare R2 binding channel မသုံးချင်လျှင်၊ သို့မဟုတ် storage provider က Cloudflare R2 မဟုတ်လျှင်။</li></ul><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>လိုအပ်ချက်</th><th>အသုံးပြုပုံ</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>object storage service ရဲ့ S3 API endpoint။</td></tr><tr><td>Bucket name</td><td>files တွေသိမ်းမယ့် bucket။</td></tr><tr><td>Region</td><td>storage region။ Cloudflare R2 အတွက် များသောအားဖြင့် <code>auto</code>။</td></tr><tr><td>Access Key ID</td><td>S3 access key ID။</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key။</td></tr><tr><td>CDN domain</td><td>file access အတွက် optional custom domain။</td></tr></tbody></table><p>Cloudflare R2 ကို S3 API ဖြင့်သုံးတဲ့ဥပမာ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="ဘယ်နေရာမှာ-ထည့်မလဲ" tabindex="-1">ဘယ်နေရာမှာ ထည့်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-ထည့်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ ထည့်မလဲ&quot;">​</a></h2><ol><li>System Settings ကိုဖွင့်ပါ။</li><li>Upload Settings ကိုသွားပါ။</li><li>ညာဘက်အပေါ်ထောင့်က Add Channel ကိုနှိပ်ပါ။</li><li><code>S3</code> ကိုရွေးပါ။</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>အသုံးပြုပုံ</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>ဒီ S3 channel အတွက် မှတ်မိလွယ်တဲ့အမည်၊ ဥပမာ <code>s3test</code> သို့မဟုတ် <code>R2-S3</code>။</td><td>Yes</td></tr><tr><td>Enable channel</td><td>ဒီ channel က upload selection ထဲပါမပါထိန်းချုပ်သည်။</td><td>Recommended</td></tr><tr><td>Endpoint</td><td><code>https://</code> ပါတဲ့ S3 service endpoint အပြည့်အစုံ။</td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>Optional။ set လုပ်ထားရင် generated file links က ဒီ domain ကိုဦးစားပေးသုံးသည်။</td><td>No</td></tr><tr><td>Bucket name</td><td>bucket name၊ ဥပမာ <code>s3test</code> သို့မဟုတ် <code>img-r2</code>။</td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region။ Cloudflare R2 အတွက် များသောအားဖြင့် <code>auto</code>။</td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID။</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key။</td><td>Yes</td></tr><tr><td>Path-style access</td><td>compatibility switch။ default off ဖြစ်သည်။ MinIO, OpenList, self-hosted S3 services အချို့မှာလိုနိုင်သည်။</td><td>No</td></tr><tr><td>Quota limit</td><td>capacity အပေါ်မူတည်ပြီး ဒီ S3 channel က upload selection ထဲပါမပါထိန်းချုပ်သည်။</td><td>No</td></tr><tr><td>Capacity limit</td><td>quota limit enabled ပြီးနောက်လိုအပ်သည်၊ ဥပမာ <code>10 GB</code>။</td><td>Required when quota limit is enabled</td></tr><tr><td>Threshold</td><td>usage က ဒီ percentage ရောက်ရင် write ရပ်သည်၊ ဥပမာ <code>90%</code>။</td><td>Required when quota limit is enabled</td></tr><tr><td>Remark</td><td>ကိုယ်တိုင် maintenance အတွက် notes။</td><td>No</td></tr></tbody></table><h2 id="cloudflare-r2-s3-api-keys-ဖန်တီးပါ" tabindex="-1">Cloudflare R2 S3 API Keys ဖန်တီးပါ <a class="header-anchor" href="#cloudflare-r2-s3-api-keys-ဖန်တီးပါ" aria-label="Permalink to &quot;Cloudflare R2 S3 API Keys ဖန်တီးပါ&quot;">​</a></h2><ol><li>Cloudflare Dashboard ကိုဖွင့်ပါ။</li><li><code>R2 Object Storage</code> ကိုသွားပါ။</li><li><code>Manage R2 API Tokens</code> သို့မဟုတ် API token management entry ကိုရှာပါ။</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>target bucket ကို access လုပ်နိုင်တဲ့ R2 API token ဖန်တီးပါ။</li></ol><p><img src="`+t+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li>generated <code>Access Key ID</code> နဲ့ <code>Secret Access Key</code> ကို copy လုပ်ပါ။</li></ol><p><img src="'+a+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>R2 bucket page ကိုပြန်သွားပြီး bucket name ကို confirm လုပ်ပါ။</li><li>account အတွက် S3 API endpoint ကိုမှတ်ပါ။ များသောအားဖြင့်ဒီလိုဖြစ်ပါတယ်:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings ကိုဖွင့်ပါ။</li><li>Add Channel ကိုနှိပ်ပါ။</li><li><code>S3</code> ကိုရွေးပါ။</li><li>မှတ်မိလွယ်တဲ့ channel name ထည့်ပါ၊ ဥပမာ <code>s3test</code>။</li><li><code>Endpoint</code> ထဲမှာ S3 API endpoint ထည့်ပါ။</li><li>custom CDN သုံးလျှင် <code>Custom CDN domain</code> ထဲထည့်ပါ၊ မသုံးလျှင်ဗလာထားပါ။</li><li>bucket name ထည့်ပါ။</li><li>region ထည့်ပါ။ Cloudflare R2 ဥပမာအတွက် <code>auto</code> သုံးပါ။</li><li>Access Key ID နဲ့ Secret Access Key ထည့်ပါ။</li><li>provider ကတိတိကျကျမလိုအပ်ဘဲ path-style access ကို off ထားပါ။</li><li>capacity control လိုချင်လျှင် quota limit enable လုပ်ပြီး capacity limit နဲ့ threshold ထည့်ပါ။</li><li>Save ကိုနှိပ်ပါ။</li></ol><p><img src="'+d+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="စစ်ဆေးနည်း" tabindex="-1">စစ်ဆေးနည်း <a class="header-anchor" href="#စစ်ဆေးနည်း" aria-label="Permalink to &quot;စစ်ဆေးနည်း&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>စစ်ဆေးပုံ</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save ပြီးနောက် Upload Settings မှာ S3 channel card ပေါ်လာရပါမယ်။</td></tr><tr><td>Channel is enabled</td><td>card ရဲ့ညာဘက်အပေါ် switch က on ဖြစ်ရပါမယ်။</td></tr><tr><td>Key fields are saved</td><td>detail view မှာ Endpoint, Bucket, Region, path-style access နဲ့ related fields တွေမြင်ရပါမယ်။</td></tr><tr><td>Upload works</td><td>test image upload လုပ်ပြီး object က target bucket ထဲရောက်လားစစ်ပါ။</td></tr><tr><td>Link opens</td><td>upload ပြီးနောက်ရတဲ့ image link ဖွင့်လို့ရရပါမယ်။</td></tr><tr><td>Capacity display works</td><td>quota limit enabled ဖြစ်လျှင် card မှာ used capacity နဲ့ configured limit ပြရပါမယ်။</td></tr></tbody></table><p>S3 capacity statistics က provider bucket ကို real time query မလုပ်ဘဲ ImgBed ရဲ့ local file records ကနေတွက်ချက်ပါတယ်။ S3 configuration save ပြီးနောက် system က current D1 records ကနေ quota ledger ကိုပြန်တွက်ပါမယ်။</p><p><img src="'+s+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="path-style-access-ကို-enable-လုပ်သင့်လား" tabindex="-1">path-style access ကို enable လုပ်သင့်လား? <a class="header-anchor" href="#path-style-access-ကို-enable-လုပ်သင့်လား" aria-label="Permalink to &quot;path-style access ကို enable လုပ်သင့်လား?&quot;">​</a></h3><p>များသောအားဖြင့် မလိုပါ။</p><p>သင့် S3-compatible provider က virtual-hosted-style URLs မထောက်ပံ့တဲ့အခါ၊ သို့မဟုတ် provider documentation က path-style access ကိုတိတိကျကျလိုအပ်တယ်ဆိုတဲ့အခါသာ enable လုပ်ပါ။</p><h3 id="cdn-domain-က-ဘာအတွက်လဲ" tabindex="-1">CDN domain က ဘာအတွက်လဲ? <a class="header-anchor" href="#cdn-domain-က-ဘာအတွက်လဲ" aria-label="Permalink to &quot;CDN domain က ဘာအတွက်လဲ?&quot;">​</a></h3><p>bucket ရှေ့မှာ CDN သို့မဟုတ် custom access domain ထားထားလျှင် ဒီမှာထည့်ပါ။</p><p>configure ပြီးနောက် generated file links က ဒီ domain ကိုဦးစားပေးသုံးပါမယ်။ CDN မသုံးလျှင်ဗလာထားပါ။</p><h3 id="upload-fail-ဖြစ်ရင်-ဘာစစ်ရမလဲ" tabindex="-1">upload fail ဖြစ်ရင် ဘာစစ်ရမလဲ? <a class="header-anchor" href="#upload-fail-ဖြစ်ရင်-ဘာစစ်ရမလဲ" aria-label="Permalink to &quot;upload fail ဖြစ်ရင် ဘာစစ်ရမလဲ?&quot;">​</a></h3><p>ပထမဦးဆုံး ဒီအချက်တွေစစ်ပါ:</p><ol><li>Endpoint မှာ <code>https://</code> ပါတဲ့ URL အပြည့်အစုံရှိလား။</li><li>bucket name မှန်လား။</li><li>Region က provider requirement နဲ့ကိုက်လား။</li><li>Access Key ID နဲ့ Secret Access Key ကိုအပြည့်အစုံ copy လုပ်ထားလား။</li><li>key မှာ target bucket အတွက် write permission ရှိလား။</li><li>provider က path-style access မလိုဘူးလား၊ လိုရင် enable လုပ်ထားလား။</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S3 Endpoint, Bucket, Region, Access Key, Secret Key ပြင်ဆင်ပါ</span></span>
<span class="line"><span>-&gt; Upload Settings ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; S3 ရွေးပါ</span></span>
<span class="line"><span>-&gt; Endpoint / Bucket / Region / Access Key / Secret Key ထည့်ပါ</span></span>
<span class="line"><span>-&gt; လိုအပ်လျှင် CDN domain ထည့်ပါ</span></span>
<span class="line"><span>-&gt; default အနေနဲ့ path-style access off ထားပါ</span></span>
<span class="line"><span>-&gt; လိုအပ်လျှင် quota limit enable လုပ်ပါ</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; test image upload လုပ်ပြီး result စစ်ပါ</span></span></code></pre></div>`,40)])])}const f=l(c,[["render",r]]);export{k as __pageData,f as default};
